import React, { useRef, useMemo, useState, useEffect } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import * as THREE from "three";
import "../style/NeuralParticles.css";

/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
   Neural Network  вЂ”  9 layers, 59 nodes
в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */

// Helper: evenly-spaced y positions for N nodes
const ys = (n, step = 0.9) =>
  Array.from({ length: n }, (_, i) => ((n - 1) / 2 - i) * step);

const LAYER_X  = [-6.0, -4.5, -3.0, -1.5, 0.0, 1.5, 3.0, 4.5, 6.0];
const LAYER_N  = [   4,    6,    8,    9,   9,   8,   7,   5,   3];
const LAYER_COLORS = [
  "#60a5fa",  // Input
  "#38bdf8",  // H1
  "#22d3ee",  // H2
  "#818cf8",  // H3
  "#a78bfa",  // H4
  "#c084fc",  // H5
  "#34d399",  // H6
  "#86efac",  // H7
  "#fb923c",  // Output
];

// Build NODES array
const NODES = [];
let id = 0;
LAYER_X.forEach((x, li) => {
  const zOff = [0.10,-0.20,0.30,-0.10,0.20,-0.30,0.15,-0.25,0.10,-0.20,0.25];
  ys(LAYER_N[li]).forEach((y, ni) => {
    NODES.push({ id: id++, pos: [x, y, zOff[ni % zOff.length]], layer: li });
  });
});

// Fully-connected between consecutive layers
const EDGES = [];
for (let i = 0; i < NODES.length; i++)
  for (let j = i + 1; j < NODES.length; j++)
    if (NODES[j].layer === NODES[i].layer + 1) EDGES.push([i, j]);

const STREAM = 6;

/* в”Ђв”Ђ Shaders в”Ђв”Ђ */
const streamVert = /* glsl */ `
  attribute float aProgress;
  varying  float vProgress;
  void main() {
    vProgress    = aProgress;
    float fade   = sin(aProgress * 3.14159);
    vec4  mv     = modelViewMatrix * vec4(position, 1.0);
    gl_Position  = projectionMatrix * mv;
    gl_PointSize = 60.0 * (0.5 + fade * 0.5) / -mv.z;
  }`;

const streamFrag = /* glsl */ `
  varying float vProgress;
  void main() {
    float d = length(gl_PointCoord - vec2(0.5));
    if (d > 0.5) discard;
    float glow = pow(1.0 - d * 2.0, 1.6);
    float fade = sin(vProgress * 3.14159);
    vec3  col  = mix(vec3(0.0, 0.95, 1.0), vec3(0.8, 0.1, 1.0), vProgress);
    gl_FragColor = vec4(col, glow * fade * 1.0);
  }`;

/* в”Ђв”Ђ Topology lines в”Ђв”Ђ */
function NetworkLines() {
  const obj = useMemo(() => {
    const pts = new Float32Array(EDGES.length * 6);
    EDGES.forEach(([a, b], i) => {
      pts.set(NODES[a].pos, i * 6);
      pts.set(NODES[b].pos, i * 6 + 3);
    });
    const geo = new THREE.BufferGeometry();
    geo.setAttribute("position", new THREE.BufferAttribute(pts, 3));
    return new THREE.LineSegments(geo, new THREE.LineBasicMaterial({
      color: "#3b6be0", transparent: true, opacity: 0.09,
      blending: THREE.AdditiveBlending,
    }));
  }, []);
  return <primitive object={obj} />;
}

/* в”Ђв”Ђ Static node sphere вЂ” no pulse, no halo в”Ђв”Ђ */
function NodeMesh({ position, layer }) {
  const color = LAYER_COLORS[layer];
  return (
    <mesh position={position}>
      <sphereGeometry args={[0.19, 14, 14]} />
      <meshBasicMaterial color={color} />
    </mesh>
  );
}

/* в”Ђв”Ђ Stream particles в”Ђв”Ђ */
function StreamParticles() {
  const { geo, sd } = useMemo(() => {
    const n       = EDGES.length * STREAM;
    const posA    = new Float32Array(n * 3);
    const posB    = new Float32Array(n * 3);
    const tArr    = new Float32Array(n);
    const spd     = new Float32Array(n);
    const livePos = new Float32Array(n * 3);
    const liveT   = new Float32Array(n);
    EDGES.forEach(([ai, bi], ei) => {
      const a = NODES[ai].pos, b = NODES[bi].pos;
      for (let p = 0; p < STREAM; p++) {
        const i = ei * STREAM + p;
        posA.set(a, i * 3); posB.set(b, i * 3);
        tArr[i] = p / STREAM;
        spd[i]  = 0.005 + Math.random() * 0.007;
        const t = tArr[i];
        livePos[i*3]   = a[0] + (b[0]-a[0])*t;
        livePos[i*3+1] = a[1] + (b[1]-a[1])*t;
        livePos[i*3+2] = a[2] + (b[2]-a[2])*t;
        liveT[i] = t;
      }
    });
    const g = new THREE.BufferGeometry();
    g.setAttribute("position",  new THREE.BufferAttribute(livePos, 3).setUsage(THREE.DynamicDrawUsage));
    g.setAttribute("aProgress", new THREE.BufferAttribute(liveT,   1).setUsage(THREE.DynamicDrawUsage));
    return { geo: g, sd: { posA, posB, tArr, spd, livePos, liveT } };
  }, []);

  useFrame(() => {
    const { posA, posB, tArr, spd, livePos, liveT } = sd;
    const n = EDGES.length * STREAM;
    for (let i = 0; i < n; i++) {
      tArr[i] += spd[i];
      if (tArr[i] > 1) tArr[i] -= 1;
      const t = tArr[i];
      livePos[i*3]   = posA[i*3]   + (posB[i*3]   - posA[i*3])   * t;
      livePos[i*3+1] = posA[i*3+1] + (posB[i*3+1] - posA[i*3+1]) * t;
      livePos[i*3+2] = posA[i*3+2] + (posB[i*3+2] - posA[i*3+2]) * t;
      liveT[i] = t;
    }
    geo.attributes.position.needsUpdate  = true;
    geo.attributes.aProgress.needsUpdate = true;
  });

  return (
    <points geometry={geo}>
      <shaderMaterial vertexShader={streamVert} fragmentShader={streamFrag}
        transparent depthWrite={false} blending={THREE.AdditiveBlending} />
    </points>
  );
}

function ParticleNet() {
  const ref = useRef();
  useFrame(({ clock }) => {
    if (ref.current) {
      const t = clock.elapsedTime;
      ref.current.rotation.y = Math.sin(t * 0.11) * 0.20;
      ref.current.rotation.x = Math.sin(t * 0.07) * 0.05;
    }
  });
  return (
    <group ref={ref} scale={1.18}>
      <NetworkLines />
      {NODES.map((nd) => <NodeMesh key={nd.id} position={nd.pos} layer={nd.layer} />)}
      <StreamParticles />
    </group>
  );
}

function LazyCanvas({ children, ...props }) {
  const wrapRef = useRef();
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setVisible(true); }, { threshold: 0.1 });
    if (wrapRef.current) obs.observe(wrapRef.current);
    return () => obs.disconnect();
  }, []);
  return (
    <div ref={wrapRef} style={{ width: "100%", height: "100%" }}>
      {visible && <Canvas {...props}>{children}</Canvas>}
    </div>
  );
}

const NeuralParticles = () => (
  <div className="neural-particles-wrap">
    <div className="neural-particles-canvas" aria-hidden="true">
      <LazyCanvas camera={{ position: [0, 0, 7.5], fov: 76 }} gl={{ antialias: true, alpha: true }}>
        <ParticleNet />
      </LazyCanvas>
    </div>
    <div className="neural-particles-legend">
      <span className="np-legend-item"><span className="np-dot" style={{ background: "#60a5fa" }} />Input</span>
      <span className="np-legend-item"><span className="np-dot" style={{ background: "#a78bfa" }} />Hidden</span>
      <span className="np-legend-item"><span className="np-dot" style={{ background: "#fb923c" }} />Output</span>
      <span className="np-legend-item"><span className="np-stream-line" />Signal</span>
    </div>

  </div>
);

export default NeuralParticles;
